import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"124. Roster","description":"","frontmatter":{"title":"124. Roster","eba":"Mental Health Services 2024-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/124-roster.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/124-roster.md"}'),n={name:"ebas/mental-health/health-professionals/hours-of-work/124-roster.md"};function a(i,e,h,l,p,c){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_124-roster" tabindex="-1">124. Roster <a class="header-anchor" href="#_124-roster" aria-label="Permalink to &quot;124. Roster&quot;">​</a></h1><p><strong>124.1</strong> A roster of at least 28 days’ duration shall be posted at least 28 days before it comes into operation at each work location in a place where it may be readily seen by such Employees and the Secretary or other accredited representative of HACSU.</p><p><strong>(a)</strong> This 28-day roster provision will operate from the next roster cycle commencing 3 months after the commencement of this Agreement</p><p><strong>(b)</strong> Roster Requirements Rosters will:</p><p><strong>(i)</strong> Set out: <strong>(A)</strong> The Employee&#39;s ordinary working hours <strong>(B)</strong> Starting and finishing times <strong>(C)</strong> Meal intervals.</p><p><strong>(ii)</strong> Provide an Employee who works 0.8 EFT or more with two consecutive days off per week. Nothing in this subclause (b) is intended to: <strong>(A)</strong> Restrict an Employee requesting single days off, including as a self- rostering request; or <strong>(B)</strong> Prevent an Employee who works 0.8 EFT or more from having a single day off rostered where they also have consecutive days off rostered that week.</p><p><strong>(iii)</strong> From the commencement of the Agreement, an Employer may use an alternative method to record meal interval allocations outlined in 124.1(b)(i)(C) if the electronic roster system being used is unable to accommodate its inclusion. This will be located in each work location where it can be readily accessible seen by such Employees and/or other representatives of the Union(s) to ensure compliance with meal break provisions, for a period of no less than 6 years.</p><p><strong>(c)</strong> Where an Employee works a set Monday to Friday arrangement of hours without change, then no roster is required to be established.</p><p><strong>(d)</strong> Seven days&#39; notice shall be given of a change in roster, except in emergency situations.</p><p><strong>(i)</strong> Rosters which include work on public holiday <strong>(A)</strong> Employers must implement a policy or procedure for the issuance and finalisation of rosters which cover the performance of work on a public holiday under the Act. <strong>(B)</strong> The policy/procedure referenced at subclause 124.1(d)(i)(A)above should: 1. Set out the process for an Employee to request not to work on a public holiday they are requested to work; and 2. Set out the process for the Employer to provide a written response to an Employee&#39;s request not to work on a public holiday they are requested to work. An Employer who receives a request under 124.1(d)(i)(B)(1.) must accept that request unless the Employer determines that the refusal is not reasonable in the</p><p>circumstances. The factors an Employer must not consider when determining whether a request is not reasonable include:</p><p><strong>(ii)</strong> Whether the Employee has clearly explained a reason for refusing to work on the relevant public holiday</p><p><strong>(iii)</strong> The nature of the Employers&#39; workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee</p><p><strong>(iv)</strong> The capacity for the Employer to find replacement Employee to perform the same work</p><p><strong>(v)</strong> The Employee&#39;s personal circumstances (including family responsibilities) to the extent that those circumstances have been disclosed to the Employer</p><p><strong>(vi)</strong> Whether the Employee could reasonably have expected the Employer to request that they work on the public holiday(s)</p><p><strong>(vii)</strong> Whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects expectation of, work on the public holiday(s)</p><p><strong>(viii)</strong> The type of employment of the Employee (e.g. whether full-time, part- time, casual or shiftwork)</p><p><strong>(ix)</strong> The amount of notice in advance of the public holiday given by the Employer when making the request</p><p><strong>(x)</strong> The amount of notice in advance of the public holiday given by the Employee when refusing the request</p><p><strong>(xi)</strong> Any other relevant matter. <strong>(C)</strong> Where the Employer has requested an Employee to work any public holiday(s) and either:</p><p><strong>(i)</strong> The Employee has not made a request not to work the public holiday in accordance with the policy or procedure referenced at subclause 124.1(d)(i)(B)above; or</p><p><strong>(ii)</strong> The Employer has determined that a request was not reasonable (taking into account the factors in subclause 124.1(d)(i)(B)(2.)), The Employer may require the Employee to work on the relevant public holiday(s).</p>',23)])])}const u=t(n,[["render",a]]);export{d as __pageData,u as default};
